+  ws.on('close', () => {
+    connectionPool.delete(wsUrl);
+    // Reject all pending requests
+    for (const [id, pending] of conn.pendingRequests) {
+      clearTimeout(pending.timeout);
+      pending.reject(new Error('Connection closed'));
